import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.BflysNKA.js";const c=JSON.parse('{"title":"补全","description":"","frontmatter":{},"headers":[],"relativePath":"api/completions.md","filePath":"api/completions.md","lastUpdated":1778577020000}'),n={name:"api/completions.md"};function l(p,s,h,o,r,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="补全" tabindex="-1">补全 <a class="header-anchor" href="#补全" aria-label="Permalink to &quot;补全&quot;">​</a></h1><p>兼容需要传统 <code>prompt</code> 形式的场景时，可以使用这个接口。</p><p>如果你是第一次写新脚本，不建议从这页开始。多数新项目优先使用 <a href="/api/chat">聊天</a>。这一页更适合已经存在的旧脚本、旧工具或只认 <code>prompt</code> 的历史集成。</p><h2 id="创建补全-post" tabindex="-1">创建补全 POST <a class="header-anchor" href="#创建补全-post" aria-label="Permalink to &quot;创建补全 POST&quot;">​</a></h2><p>地址：<code>POST https://xiaolan1.cn/v1/completions</code></p><h3 id="常用请求参数" tabindex="-1">常用请求参数 <a class="header-anchor" href="#常用请求参数" aria-label="Permalink to &quot;常用请求参数&quot;">​</a></h3><ul><li><code>model</code>：模型名称</li><li><code>prompt</code>：输入文本</li><li><code>max_tokens</code>：最大输出长度</li><li><code>temperature</code>：输出随机性</li></ul><p>这里和聊天接口最大的区别，是它直接接收一段 <code>prompt</code> 字符串，而不是 <code>messages</code> 数组。</p><p>这也是为什么它更适合旧脚本：<br> 旧程序往往只知道“把一整段文本丢进去，拿回一整段文本”，并不知道多轮消息结构是什么。</p><h2 id="第一次建议怎么测" tabindex="-1">第一次建议怎么测 <a class="header-anchor" href="#第一次建议怎么测" aria-label="Permalink to &quot;第一次建议怎么测&quot;">​</a></h2><p>第一次验证补全接口时，重点不是让模型立刻写出一篇长文，而是先把三层问题拆开：</p><ol><li>这把 Key 能不能访问 <code>/v1/completions</code></li><li>这个模型是不是支持补全接口</li><li>这段 <code>prompt</code> 本身是不是已经把输出压得太长</li></ol><p>所以第一次最好只发一条很短的 <code>prompt</code>。<br> 短 <code>prompt</code> 的意义，不是节省那几十个 token，而是让你更容易判断问题停在接口层、模型层，还是只是参数给得太激进。</p><h3 id="示例请求" tabindex="-1">示例请求 <a class="header-anchor" href="#示例请求" aria-label="Permalink to &quot;示例请求&quot;">​</a></h3><p>先把 <code>MODEL</code> 替换成你在模型广场复制、且确认支持补全接口的模型名：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;替换成模型广场里的实际模型名&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer &lt;你的 API Key&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;{</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">model</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">$MODEL</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">prompt</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">写一个 Python 读取 JSON 文件的例子</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">max_tokens</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:300}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>第一次验证时，先用一段短 prompt。这样更容易区分是接口不支持、模型不支持，还是只是输出被截断。</p><h3 id="响应" tabindex="-1">响应 <a class="header-anchor" href="#响应" aria-label="Permalink to &quot;响应&quot;">​</a></h3><p>重点看 <code>choices[0].text</code>。</p><p>如果你已经能拿到 <code>choices[0].text</code>，说明这把 Key、当前模型和补全接口链路已经正常工作。</p><p>如果响应里还能看到 <code>usage</code>，也建议顺手看一下。<br> 它能帮助你确认这次请求到底吃了多少输入和输出 token，后面你再调 <code>prompt</code> 长度和 <code>max_tokens</code> 时，会更有感觉。</p><h2 id="常见参数怎么理解" tabindex="-1">常见参数怎么理解 <a class="header-anchor" href="#常见参数怎么理解" aria-label="Permalink to &quot;常见参数怎么理解&quot;">​</a></h2><ul><li><code>prompt</code>：真正交给模型补全的原始文本</li><li><code>max_tokens</code>：这次最多允许它再往后写多少</li><li><code>temperature</code>：越高越发散，越低越稳定</li></ul><p>第一次接入时，<code>temperature</code> 不需要一开始就调。<br> 把地址、Key 和模型跑通以后，再根据业务看要不要继续追求更稳定或更开放的输出。</p><h2 id="什么时候用它" tabindex="-1">什么时候用它 <a class="header-anchor" href="#什么时候用它" aria-label="Permalink to &quot;什么时候用它&quot;">​</a></h2><ul><li>老脚本只支持 <code>prompt</code></li><li>某些第三方工具还没切到聊天接口</li><li>你明确知道当前模型支持传统补全格式</li></ul><p>新项目优先用 <a href="/api/chat">聊天</a>。</p><h2 id="迁移建议" tabindex="-1">迁移建议 <a class="header-anchor" href="#迁移建议" aria-label="Permalink to &quot;迁移建议&quot;">​</a></h2><p>如果你的脚本还能改，建议逐步迁到 <code>/v1/chat/completions</code>：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;从模型广场复制、且支持补全接口的模型名&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  &quot;messages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;user&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">&quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;原来的 prompt 内容&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>聊天接口更适合多轮上下文，也更贴近现在主流客户端。</p><p>如果你正在维护旧脚本，可以先用下面这个思路迁移：</p><ul><li>原来的 <code>prompt</code> 内容，先原样塞进一条 <code>user</code> 消息</li><li>原来靠字符串拼接实现的上下文，逐步拆成多轮 <code>messages</code></li><li>先验证输出结果，再逐步加入 <code>system</code> 规则</li></ul><p>这样比一次性重写整套提示词更稳。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="choices-为空" tabindex="-1">choices 为空 <a class="header-anchor" href="#choices-为空" aria-label="Permalink to &quot;choices 为空&quot;">​</a></h3><p>先检查模型是否支持补全接口。部分新模型只支持聊天或 Responses API。</p><p>如果你已经确认模型本身没问题，再回头看 <code>prompt</code> 是否为空、是否被 shell 转义破坏了原文。</p><h3 id="输出被截断" tabindex="-1">输出被截断 <a class="header-anchor" href="#输出被截断" aria-label="Permalink to &quot;输出被截断&quot;">​</a></h3><p>提高 <code>max_tokens</code>，或者把输入拆小。</p><p>如果你的 <code>prompt</code> 本身已经很长，再继续拉高 <code>max_tokens</code>，结果通常不是“更稳”，而是更贵也更难判断真正问题在哪。<br> 第一次排障时，优先缩短输入，通常比一味拉大参数更有效。</p><h3 id="明明模型能聊天-为什么补全接口不能用" tabindex="-1">明明模型能聊天，为什么补全接口不能用 <a class="header-anchor" href="#明明模型能聊天-为什么补全接口不能用" aria-label="Permalink to &quot;明明模型能聊天，为什么补全接口不能用&quot;">​</a></h3><p>聊天接口可用，不代表同一个模型一定支持传统补全格式。遇到这种情况，优先回模型广场确认模型能力，或者直接改走聊天接口。</p>`,43)])])}const u=a(n,[["render",l]]);export{c as __pageData,u as default};
